INSERT INTO moviment (descricao, date, process_id, visible_to_client, created_on, modified_on)
SELECT 'Distribuído por sorteio', (to_timestamp('07/02/2023', 'DD/MM/YYYY'))::timestamp, p.process_id, true, NOW(), NOW()
FROM process p
WHERE LOWER(TRIM(p.numero)) = LOWER('0801395-53.2023.8.19.0011')
AND NOT EXISTS (
  SELECT 1 FROM moviment m
  WHERE m.process_id = p.process_id
    AND m.date = (to_timestamp('07/02/2023', 'DD/MM/YYYY'))::timestamp
    AND m.descricao = 'Distribuído por sorteio'
)
LIMIT 1;
