FROM process p
WHERE LOWER(TRIM(p.numero)) = LOWER('0803120-07.2023.8.19.0002')
AND NOT EXISTS (
  SELECT 1 FROM moviment m
  WHERE m.process_id = p.process_id
    AND m.date = (to_timestamp('02/08/2023', 'DD/MM/YYYY'))::timestamp
    AND m.descricao = 'Juntada de Petição de petição'
)
LIMIT 1;
