WHERE LOWER(TRIM(p.numero)) = LOWER('0812522-49.2022.8.19.0002')
AND NOT EXISTS (
  SELECT 1 FROM moviment m
  WHERE m.process_id = p.process_id
    AND m.date = (to_timestamp('06/02/2026', 'DD/MM/YYYY'))::timestamp
    AND m.descricao = 'Publicado Intimação em 06/02/2026.'
)
LIMIT 1;
